// Extract case_id from payload for validation
const item = $input.first().json;
const caseId = item.case_id;

if (!caseId) {
  throw new Error('case_id is required');
}

return [{ json: { ...item, _case_id_valid: true } }];

// Delete files from Supabase Storage for a given case_id
const item = $input.first().json;
const caseId = item.case_id;

const supabaseUrl = "https://ncvlpqbevllqwrpdauxi.supabase.co";
const supabaseKey = "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Im5jdmxwcWJldmxscXdycGRhdXhpIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MjE1NTk2NiwiZXhwIjoyMDg3NzMxOTY2fQ.Cs5k-uKtxyiTejLzsrpJllPg3-cZ6qvFDSjEdEVnBMU";
const BUCKET = 'case_files';

async function fetchWithRetry(url, options, maxRetries = 3, delayMs = 2000) {
  for (let attempt = 1; attempt <= maxRetries; attempt++) {
    try {
      const res = await fetch(url, options);
      if (!res.ok) throw new Error(`HTTP ${res.status}: ${await res.text()}`);
      return res;
    } catch (err) {
      if (attempt === maxRetries) throw err;
      await new Promise(r => setTimeout(r, delayMs * attempt));
    }
  }
}

let files = [];
try {
  const listRes = await fetch(
    `${supabaseUrl}/storage/v1/object/list/${BUCKET}`,
    {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${supabaseKey}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({ prefix: caseId + '/' })
    }
  );
  if (listRes.ok) { files = await listRes.json(); }
} catch (e) {
  return [{ json: { ...item, storage_deleted: false, storage_error: e.message } }];
}

if (!files || files.length === 0) {
  return [{ json: { ...item, storage_deleted: true, files_deleted: 0 } }];
}

const paths = files.map(f => `${caseId}/${f.name}`);

try {
  await fetchWithRetry(
    `${supabaseUrl}/storage/v1/object/${BUCKET}`,
    {
      method: 'DELETE',
      headers: {
        'Authorization': `Bearer ${supabaseKey}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({ prefixes: paths })
    }
  );
} catch (err) {
  return [{ json: { ...item, storage_deleted: false, storage_error: err.message } }];
}

return [{ json: { ...item, storage_deleted: true, files_deleted: paths.length, storage_error: null } }];

